import javax.jws.WebMethod;
import javax.jws.WebService;
import javax.xml.soap.SOAPException;
import javax.xml.soap.SOAPMessage;
import javax.xml.soap.SOAPBody;
import javax.xml.soap.SOAPElement;
import javax.xml.soap.MessageFactory;
import javax.xml.soap.SOAPFactory;
import javax.xml.soap.SOAPPart;

@WebService
public class OrderProcessingService {

    @WebMethod
    public String processOrder(SOAPMessage request) {
        try {
            SOAPBody body = request.getSOAPBody();
            SOAPElement orderElement = (SOAPElement) body.getChildElements().next();
            String itemName = orderElement.getChildElements("itemName").next().getTextContent();
            int quantity = Integer.parseInt(orderElement.getChildElements("quantity").next().getTextContent());
            double price = Double.parseDouble(orderElement.getChildElements("price").next().getTextContent());

            double totalPrice = calculateTotalPrice(quantity, price);
            // Here you can add code to save the order in the database or process it further

            return "Order processed for " + itemName + " with total price: $" + totalPrice;
        } catch (SOAPException | NumberFormatException e) {
            return "Error processing order: " + e.getMessage();
        }
    }

    private double calculateTotalPrice(int quantity, double price) {
        return quantity * price;
    }
}